class SimpleQueue:
    def __init__(self, max_size=1000):
        self._items = []
        self._max_size = max_size

    def push(self, item):
        if len(self._items) >= self._max_size:
            self._items.pop(0)
        self._items.append(item)

    def pop(self):
        return self._items.pop(0) if self._items else None

