def calculate_tax(subtotal: Decimal, tax_rate: Decimal) -> Decimal:
    if subtotal < 0:
        raise ValueError("Subtotal cannot be negative")
    if not (0 <= tax_rate <= 1):
        raise ValueError("Tax rate must be between 0 and 1")
    return (subtotal * tax_rate).quantize(Decimal("0.01"))

